// Package adapter defines the boundary between Antiphon's platform-agnostic
// core (allocator, policy, bid channel, HUD) and the meeting platform it's
// driving — native WebRTC, Zoom-via-audio-relay, Meet-via-audio-relay, or a
// bot-as-host service like Recall.ai.
//
// See docs/decisions/0002-platform-agnostic-core.md.
package adapter

import "context"

// ParticipantID is opaque, scoped to a meeting session.
type ParticipantID string

// AudioFrame is raw PCM. Format negotiated at session start.
type AudioFrame struct {
	Participant ParticipantID // may be empty if the adapter can't split streams
	PCM         []byte        // s16le, sample rate = Capabilities.SampleRate
	Monotonic   int64         // ns since session start; for ordering across frames
}

// HUDEvent is a private message rendered only for one participant — the
// pre-cutoff feedback layer (see antiphon.md §Video input → private feedback).
type HUDEvent struct {
	Kind    string // "countdown-yield" | "two-bidders" | "over-time" | ...
	Payload map[string]any
}

// PlatformAdapter is the interface every meeting-platform integration
// implements. The allocator and HUD code talk only to this.
type PlatformAdapter interface {
	Participants(ctx context.Context) ([]ParticipantID, error)

	// AudioFrames yields a channel of frames. Per-participant if the platform
	// allows it; otherwise a single mixed stream — diarization is upstream.
	AudioFrames(ctx context.Context) (<-chan AudioFrame, error)

	// SetGain in [0, 1]. 0 = mute, 1 = pass. The relay adapters can only
	// gain the local user's outbound mic — see Capabilities.GainScope.
	SetGain(ctx context.Context, id ParticipantID, gain float32) error

	SendPrivateHUD(ctx context.Context, id ParticipantID, msg HUDEvent) error

	Capabilities() Capabilities
}

// GainScope describes which participants this adapter can control.
type GainScope int

const (
	GainScopeNone       GainScope = iota // view-only — allocator runs in advisory mode
	GainScopeLocalOnly                   // relay adapters: can only gate the local user
	GainScopeAll                         // native / bot-as-host adapters
)

type Capabilities struct {
	PerParticipantAudio bool      // false for relay adapters (one local mic stream)
	GainScope           GainScope // who we can mute
	PrivateHUD          bool
	VideoIn             bool
	SampleRate          int // typically 48000
}

