// Package relay is the audio-relay primitive: read PCM frames, apply a
// controllable gain, write PCM frames. The gain is the enforcement layer
// for any in-front-of-Zoom or in-front-of-Meet adapter.
//
// Wiring (Linux/PipeWire/PulseAudio) is in scripts/.
package relay

import (
	"encoding/binary"
	"errors"
	"io"
	"sync/atomic"
)

// Gain holds an atomically-updatable gain factor in [0, 1].
// 0 = muted, 1 = pass, 0.3 = ducked.
type Gain struct {
	bits atomic.Uint32 // bit-cast float32
}

func NewGain(initial float32) *Gain {
	g := &Gain{}
	g.Set(initial)
	return g
}

func (g *Gain) Set(v float32) {
	if v < 0 {
		v = 0
	} else if v > 1 {
		v = 1
	}
	g.bits.Store(float32bits(v))
}

func (g *Gain) Get() float32 {
	return bitsFloat32(g.bits.Load())
}

// Run streams s16le PCM from src to dst, applying the current gain to each
// sample. Frame size is internal — caller's chunking does not matter.
// Returns when src returns io.EOF or any error from either side.
func Run(src io.Reader, dst io.Writer, g *Gain) error {
	const chunk = 4096 // bytes — small enough for low latency, big enough for syscall amortization
	if chunk%2 != 0 {
		return errors.New("chunk must be even for s16le")
	}
	buf := make([]byte, chunk)
	for {
		n, err := io.ReadFull(src, buf)
		if n > 0 {
			applyGainS16LE(buf[:n], g.Get())
			if _, werr := dst.Write(buf[:n]); werr != nil {
				return werr
			}
		}
		if err != nil {
			if errors.Is(err, io.EOF) || errors.Is(err, io.ErrUnexpectedEOF) {
				return nil
			}
			return err
		}
	}
}

// applyGainS16LE scales each int16 sample in-place. Hot path; keep tight.
func applyGainS16LE(b []byte, gain float32) {
	if gain == 1.0 {
		return
	}
	if gain == 0.0 {
		clear(b)
		return
	}
	for i := 0; i+1 < len(b); i += 2 {
		s := int16(binary.LittleEndian.Uint16(b[i:]))
		scaled := float32(s) * gain
		// no rounding needed — gain in [0,1] so |scaled| <= |s|, no overflow
		binary.LittleEndian.PutUint16(b[i:], uint16(int16(scaled)))
	}
}

// float32bits/bitsFloat32 are math.Float32bits/Float32frombits inlined to
// keep the package math-free (and easier to grep).
func float32bits(f float32) uint32 {
	return *(*uint32)(unsafePtr(&f))
}
func bitsFloat32(b uint32) float32 {
	return *(*float32)(unsafePtr(&b))
}

