package relay

import (
	"bufio"
	"context"
	"fmt"
	"net"
	"os"
	"strconv"
	"strings"
)

// ServeControl listens on a Unix domain socket and accepts line-oriented
// commands that mutate g:
//
//	MUTE              -> gain 0
//	UNMUTE            -> gain 1
//	DUCK              -> gain 0.3
//	GAIN <float>      -> gain <float> clamped to [0,1]
//	GET               -> reply with current gain
//
// One connection at a time is plenty — the allocator is the only client.
func ServeControl(ctx context.Context, sockPath string, g *Gain) error {
	_ = os.Remove(sockPath)
	ln, err := net.Listen("unix", sockPath)
	if err != nil {
		return err
	}
	go func() {
		<-ctx.Done()
		_ = ln.Close()
		_ = os.Remove(sockPath)
	}()

	for {
		conn, err := ln.Accept()
		if err != nil {
			if ctx.Err() != nil {
				return nil
			}
			return err
		}
		go handle(conn, g)
	}
}

func handle(c net.Conn, g *Gain) {
	defer c.Close()
	sc := bufio.NewScanner(c)
	for sc.Scan() {
		reply := dispatch(strings.TrimSpace(sc.Text()), g)
		if _, err := fmt.Fprintln(c, reply); err != nil {
			return
		}
	}
}

func dispatch(line string, g *Gain) string {
	if line == "" {
		return "ERR empty"
	}
	parts := strings.Fields(line)
	cmd := strings.ToUpper(parts[0])
	switch cmd {
	case "MUTE":
		g.Set(0)
		return "OK 0"
	case "UNMUTE":
		g.Set(1)
		return "OK 1"
	case "DUCK":
		g.Set(0.3)
		return "OK 0.3"
	case "GAIN":
		if len(parts) != 2 {
			return "ERR usage: GAIN <float>"
		}
		v, err := strconv.ParseFloat(parts[1], 32)
		if err != nil {
			return "ERR " + err.Error()
		}
		g.Set(float32(v))
		return fmt.Sprintf("OK %g", g.Get())
	case "GET":
		return fmt.Sprintf("OK %g", g.Get())
	default:
		return "ERR unknown cmd: " + cmd
	}
}

