package relay

import (
	"bytes"
	"encoding/binary"
	"testing"
)

func TestGainClamp(t *testing.T) {
	g := NewGain(0)
	g.Set(-0.5)
	if g.Get() != 0 {
		t.Fatalf("expected 0, got %v", g.Get())
	}
	g.Set(2.0)
	if g.Get() != 1 {
		t.Fatalf("expected 1, got %v", g.Get())
	}
}

func TestApplyGainHalf(t *testing.T) {
	samples := []int16{1000, -2000, 30000, -30000}
	buf := make([]byte, len(samples)*2)
	for i, s := range samples {
		binary.LittleEndian.PutUint16(buf[i*2:], uint16(s))
	}
	applyGainS16LE(buf, 0.5)
	got := make([]int16, len(samples))
	for i := range samples {
		got[i] = int16(binary.LittleEndian.Uint16(buf[i*2:]))
	}
	want := []int16{500, -1000, 15000, -15000}
	for i := range want {
		if got[i] != want[i] {
			t.Errorf("sample %d: got %d, want %d", i, got[i], want[i])
		}
	}
}

func TestApplyGainMute(t *testing.T) {
	buf := []byte{0x11, 0x22, 0x33, 0x44}
	applyGainS16LE(buf, 0)
	if !bytes.Equal(buf, []byte{0, 0, 0, 0}) {
		t.Fatalf("mute should zero buffer, got %x", buf)
	}
}

func TestRunPassesThroughAtGain1(t *testing.T) {
	in := []byte{0x10, 0x20, 0x30, 0x40, 0x50, 0x60}
	src := bytes.NewReader(in)
	var dst bytes.Buffer
	g := NewGain(1)
	if err := Run(src, &dst, g); err != nil {
		t.Fatal(err)
	}
	if !bytes.Equal(in, dst.Bytes()) {
		t.Fatalf("pass-through mismatch: in %x out %x", in, dst.Bytes())
	}
}

