// antiphon-relay is the audio-relay primitive. It reads s16le PCM from
// stdin, applies a controllable gain, writes s16le PCM to stdout, and
// listens on a Unix socket for control commands (MUTE/UNMUTE/DUCK/GAIN).
//
// Wire it into PipeWire/PulseAudio via scripts/wire-relay.sh.
package main

import (
	"context"
	"flag"
	"fmt"
	"log"
	"os"
	"os/signal"
	"syscall"

	"github.com/jstimatze/antiphon/internal/relay"
)

func main() {
	sock := flag.String("ctl", "/tmp/antiphon-relay.sock", "control socket path")
	initial := flag.Float64("gain", 1.0, "initial gain (0..1)")
	flag.Parse()

	g := relay.NewGain(float32(*initial))

	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	go func() {
		if err := relay.ServeControl(ctx, *sock, g); err != nil {
			log.Printf("control socket: %v", err)
		}
	}()
	fmt.Fprintf(os.Stderr, "antiphon-relay: control on %s, initial gain=%g\n", *sock, g.Get())

	if err := relay.Run(os.Stdin, os.Stdout, g); err != nil {
		log.Fatalf("relay: %v", err)
	}
}

