const REASON_WEIGHTS: Record<AllocatorState["meetingMode"], Record<Reason, number>> = {
  // brainstorm: build-on dominant, disagreement softened (don't break flow)
  brainstorm: { "build-on": 1.4, question: 1.1, disagree: 0.7, "time-check": 0.5 },
  // decide: disagree + question dominant; build-on still useful
  decide:     { "build-on": 1.0, question: 1.3, disagree: 1.4, "time-check": 1.1 },
  // inform: questions dominant; this is the one mode where airtime equality matters less
  inform:     { "build-on": 0.6, question: 1.6, disagree: 0.8, "time-check": 1.2 },
  // socialize: open auction, no strong policy
  socialize:  { "build-on": 1.0, question: 1.0, disagree: 1.0, "time-check": 1.0 },
};

// Quiet-bidder boost: DiMicco 2004 — visible feedback fixes loud speakers
// but doesn't reliably raise quiet ones. The allocator has to actively
// recruit. Concretely: low cumulative airtime gets a multiplicative bump.
function quietBidderBoost(p: Participant): number {
  // budget remaining relative to a notional starting budget — higher remaining
  // = less spoken so far = more boost. Cap the boost.
  const remainingFraction = Math.max(0, Math.min(1, p.budgetSec / 300));
  return 1 + 0.5 * remainingFraction;
}

// Turn-cap pressure: as the current speaker exceeds the soft cap, the
// allocator's threshold for handoff drops.
function handoffPressure(state: AllocatorState): number {
  const over = Math.max(0, state.speakerHeldSec - state.softTurnCapSec);
  // 0 at the cap, 1.0 by 2× the cap
  return Math.min(1, over / state.softTurnCapSec);
}

export interface AllocationResult {
  speakerId: string | null;
  onDeckId: string | null;
  reasons: Record<string, string>; // diagnostic — why each participant got their role
}

// Allocate is the policy function called on each tick (and ideally during
// the current turn, predictively — see antiphon.md §Operational requirements).
export function allocate(
  participants: Participant[],
  state: AllocatorState,
  currentSpeakerId: string | null,
): AllocationResult {
  const reasons: Record<string, string> = {};
  const modeWeights = REASON_WEIGHTS[state.meetingMode];

  // Score each participant.
  const scored = participants.map((p) => {
    const reasonWeight = modeWeights[p.reason];
    const quietBoost = quietBidderBoost(p);
    const score = p.bid * reasonWeight * quietBoost;
    reasons[p.id] =
      `bid=${p.bid.toFixed(2)} · reason=${p.reason}(×${reasonWeight}) ` +
      `· quietBoost=×${quietBoost.toFixed(2)} → ${score.toFixed(3)}`;
    return { p, score };
  });

  // The current speaker holds the floor unless handoff pressure + a higher bid
  // crosses the threshold.
  const pressure = handoffPressure(state);
  const cur = scored.find((s) => s.p.id === currentSpeakerId);
  const others = scored.filter((s) => s.p.id !== currentSpeakerId).sort((a, b) => b.score - a.score);
  const best = others[0];

  let speaker = currentSpeakerId;
  if (!cur || !best) {
    speaker = best?.p.id ?? null;
  } else {
    // handoff if other's score exceeds current's score by (1 - pressure).
    // pressure 0 → must be much higher; pressure 1 → any tie hands off.
    const threshold = cur.score * (1 - 0.4 * pressure);
    if (best.score > threshold) {
      speaker = best.p.id;
      reasons[best.p.id] += ` ★ wins handoff (pressure=${pressure.toFixed(2)})`;
    } else {
      reasons[cur.p.id] += ` ★ holds floor (pressure=${pressure.toFixed(2)})`;
    }
  }

  // On-deck = highest scorer who isn't speaking.
  const onDeck = others.find((s) => s.p.id !== speaker)?.p.id ?? null;

  return { speakerId: speaker, onDeckId: onDeck, reasons };
}

export function applyRoles(
  participants: Participant[],
  speakerId: string | null,
  onDeckId: string | null,
): Participant[] {
  return participants.map((p) => {
    let role: Role = "idle";
    if (p.id === speakerId) role = "speaker";
    else if (p.id === onDeckId) role = "on-deck";
    return { ...p, role };
  });
