	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"
)

// cmdInit wires bmg's hooks into Claude Code's settings.json and,
// optionally, registers bmg as an MCP server in ~/.claude.json. The
// two surfaces live in different files because Claude Code sources
// them from different places:
//
//   - HOOKS come from ~/.claude/settings.json (user) or
//     <cwd>/.claude/settings.json (--project). Both scopes are honored.
//   - mcpServers come from ~/.claude.json EXCLUSIVELY. Entries placed
//     in either settings.json file are silently ignored by CC's MCP
//     discovery — verified live in CC 2.1.126.
//
// `bmg init --project --enable-mcp` therefore writes hooks to the
// project's settings.json and MCP to ~/.claude.json — the project
// flag governs only the hook scope.
//
// Each file is backed up to a timestamped sibling before any mutation.
// Foreign hooks / MCP entries are preserved on both reads and writes.
func cmdInit(args []string) {
	fs := flag.NewFlagSet("init", flag.ExitOnError)
	project := fs.Bool("project", false, "install hooks into <cwd>/.claude/settings.json instead of ~/.claude/settings.json (MCP registration, if enabled, always goes to ~/.claude.json)")
	enableMCP := fs.Bool("enable-mcp", false, "also register the bmg MCP server (mcpServers.bemygeminis) in ~/.claude.json — exposes bmg_describe to Claude")
	_ = fs.Parse(args)

	exe, err := os.Executable()
	if err != nil {
		fmt.Fprintf(os.Stderr, "bmg init: cannot find own path: %s\n", err)
		os.Exit(1)
	}
	if abs, err := filepath.Abs(exe); err == nil {
		exe = abs
	}

	hookPath, err := settingsPath(*project)
	if err != nil {
		fmt.Fprintf(os.Stderr, "bmg init: %s\n", err)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "bmg init (binary: %s)\n", exe)
	fmt.Fprintf(os.Stderr, "  hooks target:  %s\n", hookPath)

	changed, backup, err := mergeClaudeSettings(hookPath, exe)
	if err != nil {
		fmt.Fprintf(os.Stderr, "  settings.json: %s\n", err)
		os.Exit(1)
	}
	if !changed {
		fmt.Fprintln(os.Stderr, "  settings.json: already installed, no changes")
	} else {
		fmt.Fprintln(os.Stderr, "  settings.json: bmg PreToolUse:Read + SessionStart hooks installed")
		if backup != "" {
			fmt.Fprintf(os.Stderr, "  hooks backup:  %s\n", backup)
		}
	}

	if *enableMCP {
		cjPath, err := claudeJSONPath()
		if err != nil {
			fmt.Fprintf(os.Stderr, "bmg init: %s\n", err)
			os.Exit(1)
		}
		fmt.Fprintf(os.Stderr, "  MCP target:    %s\n", cjPath)
		mcpChanged, mcpBackup, err := mergeClaudeJSON(cjPath, exe)
		if err != nil {
			fmt.Fprintf(os.Stderr, "  .claude.json:  %s\n", err)
			os.Exit(1)
		}
		if !mcpChanged {
			fmt.Fprintln(os.Stderr, "  .claude.json:  bemygeminis MCP already registered, no changes")
		} else {
			fmt.Fprintln(os.Stderr, "  .claude.json:  bemygeminis MCP server registered")
			if mcpBackup != "" {
				fmt.Fprintf(os.Stderr, "  MCP backup:    %s\n", mcpBackup)
			}
		}
	}

	if changed || *enableMCP {
		fmt.Fprintln(os.Stderr, "\nRestart Claude Code so the hook and MCP registration are loaded")
		fmt.Fprintln(os.Stderr, "(both files are snapshot at session start; not hot-reloaded).")
	}
}

// cmdUninstall is the inverse of cmdInit: strips every bmg-owned hook
// entry from the target settings.json AND strips the bemygeminis
// MCP entry from ~/.claude.json. Foreign hooks and foreign MCP
// servers are left untouched. If a hooks block or mcpServers block
// is empty after stripping, the key is dropped so files don't
// accumulate empty containers across install/uninstall cycles.
func cmdUninstall(args []string) {
	fs := flag.NewFlagSet("uninstall", flag.ExitOnError)
	project := fs.Bool("project", false, "uninstall hooks from <cwd>/.claude/settings.json instead of ~/.claude/settings.json")
	_ = fs.Parse(args)

	hookPath, err := settingsPath(*project)
	if err != nil {
		fmt.Fprintf(os.Stderr, "bmg uninstall: %s\n", err)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "bmg uninstall\n  hooks target: %s\n", hookPath)
	changed, err := unmergeClaudeSettings(hookPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "  settings.json: %s\n", err)
		os.Exit(1)
	}
	if changed {
		fmt.Fprintln(os.Stderr, "  settings.json: bmg hooks removed")
	} else {
		fmt.Fprintln(os.Stderr, "  settings.json: no bmg hooks present, no changes")
	}

	cjPath, err := claudeJSONPath()
	if err != nil {
		fmt.Fprintf(os.Stderr, "bmg uninstall: %s\n", err)
		os.Exit(1)
	}
	fmt.Fprintf(os.Stderr, "  MCP target:   %s\n", cjPath)
	mcpChanged, err := unmergeClaudeJSON(cjPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "  .claude.json: %s\n", err)
		os.Exit(1)
	}
	if mcpChanged {
		fmt.Fprintln(os.Stderr, "  .claude.json: bemygeminis MCP server removed")
	} else {
		fmt.Fprintln(os.Stderr, "  .claude.json: no bemygeminis MCP entry present, no changes")
	}
}

// settingsPath resolves the hooks-file install target. Project-mode
// resolves to the cwd's .claude/settings.json (matching CC's project-
// level hook discovery); user-mode is ~/.claude/settings.json.
func settingsPath(project bool) (string, error) {
	if project {
		cwd, err := os.Getwd()
		if err != nil {
			return "", err
		}
		return filepath.Join(cwd, ".claude", "settings.json"), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(home, ".claude", "settings.json"), nil
}

// claudeJSONPath resolves the MCP-server registration target. This
// is always ~/.claude.json — CC reads mcpServers from this file
// exclusively. Verified live in CC 2.1.126 (servers registered in
// either settings.json scope are silently ignored).
func claudeJSONPath() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(home, ".claude.json"), nil
}

// mergeClaudeSettings installs bmg's hooks into the JSON file at path.
// Returns (changed, backup, err):
//   - changed=false → file was already up-to-date; no rewrite, no backup.
//   - changed=true & backup=="" → file did not previously exist.
//   - changed=true & backup!="" → existing file was backed up to that path.
//
// File mode is preserved on rewrite so a 0600 file stays 0600.
// MCP registration is handled separately by [mergeClaudeJSON] — this
// function only manages hooks.
func mergeClaudeSettings(path, exe string) (changed bool, backupPath string, err error) {
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return false, "", err
	}

	var (
		settingsMode os.FileMode = 0o600
		settings     map[string]any
		existed      bool
		original     []byte
	)

	original, err = os.ReadFile(path)
	switch {
	case err == nil:
		existed = true
		if info, statErr := os.Stat(path); statErr == nil {
			settingsMode = info.Mode().Perm()
		}
		if err := json.Unmarshal(original, &settings); err != nil {
			return false, "", fmt.Errorf("existing settings.json is invalid JSON: %w", err)
		}
	case errors.Is(err, os.ErrNotExist):
		settings = map[string]any{}
	default:
		return false, "", err
	}
	if settings == nil {
		settings = map[string]any{}
	}

	before, _ := json.Marshal(settings)

	hooks, _ := settings["hooks"].(map[string]any)
	if hooks == nil {
		hooks = map[string]any{}
	}
	upsertBmgHook(hooks, "PreToolUse", "Read", exe+" hook pre-read")
	upsertBmgHook(hooks, "SessionStart", "", exe+" hook session-start")
	settings["hooks"] = hooks

	after, _ := json.Marshal(settings)
	if string(before) == string(after) {
		return false, "", nil
	}

	if existed {
		backupPath = path + ".bmg-backup-" + time.Now().Format("20060102-150405")
		if err := os.WriteFile(backupPath, original, 0o600); err != nil {
			return false, "", fmt.Errorf("backup: %w", err)
		}
	}

	out, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return false, "", err
	}
	if err := os.WriteFile(path, append(out, '\n'), settingsMode); err != nil {
		return false, "", err
	}
	return true, backupPath, nil
}

// mergeClaudeJSON installs bmg's MCP server registration into the
// JSON file at path (~/.claude.json). Matches the existing-server
// shape in that file ("type": "stdio"). Foreign mcpServers entries
// are preserved. A timestamped backup is written before any mutation
// because ~/.claude.json is large and Claude-managed; if anything
// goes sideways the user can restore.
//
// Returns the same (changed, backup, err) shape as mergeClaudeSettings.
func mergeClaudeJSON(path, exe string) (changed bool, backupPath string, err error) {
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return false, "", err
	}

	var (
		fileMode os.FileMode = 0o600
		root     map[string]any
		existed  bool
		original []byte
	)

	original, err = os.ReadFile(path)
	switch {
	case err == nil:
		existed = true
		if info, statErr := os.Stat(path); statErr == nil {
			fileMode = info.Mode().Perm()
		}
		if err := json.Unmarshal(original, &root); err != nil {
			return false, "", fmt.Errorf("existing ~/.claude.json is invalid JSON: %w", err)
		}
	case errors.Is(err, os.ErrNotExist):
		root = map[string]any{}
	default:
		return false, "", err
	}
	if root == nil {
		root = map[string]any{}
	}

	before, _ := json.Marshal(root)

	mcps, _ := root["mcpServers"].(map[string]any)
	if mcps == nil {
		mcps = map[string]any{}
	}
	mcps["bemygeminis"] = map[string]any{
		"type":    "stdio",
		"command": exe,
		"args":    []any{"mcp"},
		"env":     map[string]any{},
	}
	root["mcpServers"] = mcps

	after, _ := json.Marshal(root)
	if string(before) == string(after) {
		return false, "", nil
	}

	if existed {
		backupPath = path + ".bmg-backup-" + time.Now().Format("20060102-150405")
		if err := os.WriteFile(backupPath, original, 0o600); err != nil {
			return false, "", fmt.Errorf("backup: %w", err)
		}
	}

	out, err := json.MarshalIndent(root, "", "  ")
	if err != nil {
		return false, "", err
	}
	if err := os.WriteFile(path, append(out, '\n'), fileMode); err != nil {
		return false, "", err
	}
	return true, backupPath, nil
}

// upsertBmgHook ensures cmd is registered under hooks[event] for the
// given matcher. Any existing bmg-owned entries for this event are
// stripped first — that way a stale binary path (e.g. /tmp/bmg-test
// from earlier development) gets replaced cleanly on the next install
// instead of accumulating duplicates. Foreign hooks under the same
// matcher are preserved.
func upsertBmgHook(hooks map[string]any, event, matcher, cmd string) {
	list, _ := hooks[event].([]any)

	filtered := make([]any, 0, len(list)+1)
	for _, entry := range list {
		em, ok := entry.(map[string]any)
		if !ok {
			filtered = append(filtered, entry)
			continue
		}
		inner, _ := em["hooks"].([]any)
		survivors := make([]any, 0, len(inner))
		for _, h := range inner {
			hm, ok := h.(map[string]any)
			if !ok {
				survivors = append(survivors, h)
				continue
			}
			if c, _ := hm["command"].(string); !isBmgCmd(c) {
				survivors = append(survivors, h)
			}
		}
		if len(survivors) == 0 {
			// Block contained only bmg entries — drop the matcher
			// wrapper entirely so we don't leave dangling empty
			// {"matcher": "Read", "hooks": []} blocks.
			continue
		}
		em["hooks"] = survivors
		filtered = append(filtered, em)
	}

	filtered = append(filtered, map[string]any{
		"matcher": matcher,
		"hooks": []any{
			map[string]any{"type": "command", "command": cmd},
		},
	})

	hooks[event] = filtered
}

// unmergeClaudeSettings strips every bmg-owned hook entry. Empty matcher
// blocks and empty event lists are removed, and "hooks" is dropped if
// nothing is left under it. Returns (changed, err).
//
// MCP registration is handled separately by [unmergeClaudeJSON].
func unmergeClaudeSettings(path string) (bool, error) {
	var settingsMode os.FileMode = 0o600
	if info, err := os.Stat(path); err == nil {
		settingsMode = info.Mode().Perm()
	}

	data, err := os.ReadFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return false, nil
		}
		return false, err
	}
	var settings map[string]any
	if err := json.Unmarshal(data, &settings); err != nil {
		return false, fmt.Errorf("settings.json is invalid JSON: %w", err)
	}

	before, _ := json.Marshal(settings)

	hooks, _ := settings["hooks"].(map[string]any)
	if hooks != nil {
		for event, val := range hooks {
			list, ok := val.([]any)
			if !ok {
				continue
			}
			filtered := make([]any, 0, len(list))
			for _, entry := range list {
				em, ok := entry.(map[string]any)
				if !ok {
					filtered = append(filtered, entry)
					continue
				}
				inner, _ := em["hooks"].([]any)
				survivors := make([]any, 0, len(inner))
				for _, h := range inner {
					hm, ok := h.(map[string]any)
					if !ok {
						survivors = append(survivors, h)
						continue
					}
					if c, _ := hm["command"].(string); !isBmgCmd(c) {
						survivors = append(survivors, h)
					}
				}
				if len(survivors) == 0 {
					continue
				}
				em["hooks"] = survivors
				filtered = append(filtered, em)
			}
			if len(filtered) == 0 {
				delete(hooks, event)
			} else {
				hooks[event] = filtered
			}
		}
		if len(hooks) == 0 {
			delete(settings, "hooks")
		}
	}

	after, _ := json.Marshal(settings)
	if string(before) == string(after) {
		return false, nil
	}

	out, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return false, err
	}
	return true, os.WriteFile(path, append(out, '\n'), settingsMode)
}

// unmergeClaudeJSON strips the bemygeminis entry from
// root.mcpServers. If mcpServers becomes empty, the key is removed.
// Returns (changed, err); missing file is a clean no-op.
func unmergeClaudeJSON(path string) (bool, error) {
	var fileMode os.FileMode = 0o600
	if info, err := os.Stat(path); err == nil {
		fileMode = info.Mode().Perm()
	}

	data, err := os.ReadFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return false, nil
		}
		return false, err
	}
	var root map[string]any
	if err := json.Unmarshal(data, &root); err != nil {
		return false, fmt.Errorf("~/.claude.json is invalid JSON: %w", err)
	}

	before, _ := json.Marshal(root)

	if mcps, _ := root["mcpServers"].(map[string]any); mcps != nil {
		delete(mcps, "bemygeminis")
		if len(mcps) == 0 {
			delete(root, "mcpServers")
		} else {
			root["mcpServers"] = mcps
		}
	}

	after, _ := json.Marshal(root)
	if string(before) == string(after) {
		return false, nil
	}

	out, err := json.MarshalIndent(root, "", "  ")
	if err != nil {
		return false, err
	}
	return true, os.WriteFile(path, append(out, '\n'), fileMode)
}

// isBmgCmd recognizes a settings.json command string as one bmg
// installed. The shape is "<path>/bmg hook <subcommand>" where
// subcommand is one of our hook handlers. Matching by basename means
// install + uninstall stay symmetric across binary moves: a stale
// /tmp/bmg-test/bmg path is still recognized as ours and replaced.
func isBmgCmd(cmd string) bool {
	fields := strings.Fields(cmd)
	if len(fields) < 3 {
		return false
	}
	base := strings.TrimSuffix(filepath.Base(fields[0]), ".exe")
	if base != "bmg" {
		return false
	}
	if fields[1] != "hook" {
		return false
	}
	switch fields[2] {
	case "pre-read", "session-start", "deny-inline":
		return true
	}
	return false
}

#!/usr/bin/env python3
# /// script
# requires-python = ">=3.8"
# dependencies = []
# ///
"""flock — a flock of geese on every keypress, system-wide, via raw evdev.

Reads /dev/input/event* directly, so it honks in every app on Wayland, X11 and
the bare TTY: it taps the kernel input layer *below* the display server, which
is exactly why no single app (a browser, xdotool, wtype, ...) can fake or
suppress it. No third-party deps. You must be in the `input` group (no root).

Usage:  honk.py [PACK]
  PACK  a directory of .wav files, or a pack name under ./honks/
        (default: goose)
"""
import glob
import os
import random
import select
import struct
import subprocess
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
HONKS_DIR = os.path.join(HERE, "honks")

# struct input_event on 64-bit Linux: timeval (2x long) + u16 type + u16 code + s32 value
EV_FMT = "llHHi"
EV_SIZE = struct.calcsize(EV_FMT)  # 24
EV_KEY = 0x01
KEY_DOWN = 1     # 0=up, 1=down, 2=autorepeat -> we honk only on the initial press
MAX_VOICES = 12  # concurrency ceiling so fast typing / key-repeat can't fork-bomb the box


def find_keyboards():
    """Auto-detect real typing keyboards from /proc/bus/input/devices.

    A real keyboard exposes a large KEY capability bitmask; power/sleep/lid
    buttons expose a tiny one. We keep devices with a `kbd` handler whose KEY
    bitmask is long, which filters out the junk pseudo-keyboards.
    """
    kbds = []
    try:
        with open("/proc/bus/input/devices") as f:
            blocks = f.read().split("\n\n")
    except OSError:
        return kbds
    for b in blocks:
        dev, key_bits = None, ""
        for line in b.splitlines():
            if line.startswith("H:") and "kbd" in line:
                for tok in line.split():
                    if tok.startswith("event"):
                        dev = "/dev/input/" + tok
            elif line.startswith("B: KEY="):
                key_bits = line.split("=", 1)[1].strip()
        if dev and len(key_bits.replace(" ", "")) > 30:
            kbds.append(dev)
    return kbds


def resolve_pack(arg):
    """A real .wav dir, a pack name under ./honks/, else the default goose pack."""
    if arg:
        cand = os.path.expanduser(arg)
        if os.path.isdir(cand):
            return cand
        cand = os.path.join(HONKS_DIR, arg)
        if os.path.isdir(cand):
            return cand
    return os.path.join(HONKS_DIR, "goose")


def main():
    pack = resolve_pack(sys.argv[1] if len(sys.argv) > 1 else "")
    sounds = sorted(glob.glob(os.path.join(pack, "*.wav")))
    if not sounds:
        sys.exit(f"flock: no .wav files in {pack}")

    devs = find_keyboards()
    if not devs:
        sys.exit("flock: no keyboards found (are you in the 'input' group?)")

    fds = {}
    for d in devs:
        try:
            fds[os.open(d, os.O_RDONLY)] = d
        except OSError as e:
            print(f"flock: skip {d}: {e}", file=sys.stderr)
    if not fds:
        sys.exit("flock: could not open any keyboard device")

    print(
        f"flock: {len(sounds)} honks from {pack} on {len(fds)} keyboard(s). Ctrl-C to stop.",
        file=sys.stderr,
    )

    last = None
    voices = []  # live paplay procs = simultaneous flock voices
    while fds:
        ready, _, _ = select.select(list(fds), [], [])
        for fd in ready:
            try:
                data = os.read(fd, EV_SIZE * 64)
            except OSError:  # keyboard unplugged / virtual device destroyed
                print(f"flock: {fds[fd]} went away", file=sys.stderr)
                os.close(fd)
                del fds[fd]
                continue
            for off in range(0, len(data) - EV_SIZE + 1, EV_SIZE):
                _, _, etype, _code, value = struct.unpack(EV_FMT, data[off : off + EV_SIZE])
                if etype == EV_KEY and value == KEY_DOWN:
                    voices = [p for p in voices if p.poll() is None]  # reap finished honks
                    if len(voices) >= MAX_VOICES:
                        continue  # flock already at full throat
                    s = random.choice(sounds)
                    while len(sounds) > 1 and s == last:  # no immediate repeat
                        s = random.choice(sounds)
                    last = s
                    if os.environ.get("HONK_DEBUG"):
                        print(f"honk! -> {os.path.basename(s)}", file=sys.stderr, flush=True)
                    voices.append(
                        subprocess.Popen(
                            ["paplay", s],
                            stdout=subprocess.DEVNULL,
                            stderr=subprocess.DEVNULL,
                        )
                    )


if __name__ == "__main__":
    try:
        main()
    except KeyboardInterrupt:
        pass
